module top_module(A, B, SUB, SUM);input [3:0] A, B;
  input SUB;
  output reg [3:0] SUM;  // Change output to reg type

  reg [3:0] obf_temp;

  always @(*) begin
    if(SUB == 0) begin
      obf_temp = A + B;
      SUM = obf_temp;
    end
    else begin
      obf_temp = A - B;
      SUM = obf_temp;
    end
  end
endmodule
